SELECT RTRIM(MOCTY.UDF05) UDF05, A.DOC_NO, ITEM.ITEM_CODE, (MO_D.REQU_INCLUDE_MULT_QTY / A.PLAN_QTY * TY004) TB004, (SELECT ISNULL(SUM(qty), 0) FROM inv_barcode_transaction WHERE lot_att01 = MOCTY.UDF05 AND item_no = ITEM.ITEM_CODE) TB005, MO_D.ISSUED_QTY gdIssuedQty, MO_D.REQU_INCLUDE_MULT_QTY gdRequQty, UNIT.UNIT_NAME, UNIT.UNIT_CODE, -- ITEM_PLANT.UDF021 BIN_CODE,WAREHOUSE.WAREHOUSE_NAME,WAREHOUSE.WAREHOUSE_CODE, MO_D.ITEM_DESCRIPTION, MO_D.ITEM_SPECIFICATION FROM MOCTY LEFT JOIN MO A ON A.DOC_NO = CONCAT(RTRIM(TY001 COLLATE Chinese_PRC_CS_AS), '-', RTRIM(TY002 COLLATE Chinese_PRC_CS_AS)) LEFT JOIN MO_D ON MO_D.MO_ID = A.MO_ID LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = MO_D.ITEM_ID -- LEFT JOIN ITEM_WAREHOUSE ON ITEM_WAREHOUSE.ITEM_ID = ITEM.ITEM_BUSINESS_ID -- LEFT JOIN WAREHOUSE ON WAREHOUSE.WAREHOUSE_ID = ITEM_WAREHOUSE.WAREHOUSE_ID LEFT JOIN ITEM_PLANT ON ITEM_PLANT.ITEM_ID = MO_D.ITEM_ID AND ITEM_PLANT.Owner_Org_ROid = A.Owner_Org_ROid LEFT JOIN UNIT ON UNIT.UNIT_ID = MO_D.UNIT_ID WHERE TY004 > 0 AND A.STATUS != 'Y' AND A.STATUS != 'y' AND A.ApproveStatus = 'Y' AND ITEM_PLANT.ISSUE_TYPE = '0'
AND MOCTY.UDF05 IN (
#{id.udf05}
)

SELECT MO_D.MO_D_ID UDF05, A.DOC_NO, ITEM.ITEM_CODE, 0 TB004, 0 TB005, MO_D.ISSUED_QTY gdIssuedQty, MO_D.REQU_INCLUDE_MULT_QTY gdRequQty, UNIT.UNIT_NAME, UNIT.UNIT_CODE, MO_D.ITEM_DESCRIPTION, MO_D.ITEM_SPECIFICATION FROM MO A LEFT JOIN MO_D ON MO_D.MO_ID = A.MO_ID LEFT JOIN ITEM ON ITEM.ITEM_BUSINESS_ID = MO_D.ITEM_ID -- LEFT JOIN ITEM_WAREHOUSE ON ITEM_WAREHOUSE.ITEM_ID = ITEM.ITEM_BUSINESS_ID -- LEFT JOIN WAREHOUSE ON WAREHOUSE.WAREHOUSE_ID = ITEM_WAREHOUSE.WAREHOUSE_ID LEFT JOIN ITEM_PLANT ON ITEM_PLANT.ITEM_ID = MO_D.ITEM_ID AND ITEM_PLANT.Owner_Org_ROid = A.Owner_Org_ROid LEFT JOIN UNIT ON UNIT.UNIT_ID = MO_D.UNIT_ID --TY004 > 0 AND --A.STATUS != 'Y' AND A.STATUS != 'y' AND A.ApproveStatus = 'Y' AND ITEM_PLANT.ISSUE_TYPE = '0'
AND A.DOC_NO IN (
#{id.ty002}
)

SELECT id, doc_no docNo, item_code itemCode, business_qty businessQty,
       match_qty matchQty, current_num currentNum, warehouse_code warehouseCode,
       warehouse_name warehouseName, bin_code binCode, unit_code unitCode, unit_name unitName, barcode,
       item_name itemName, item_spec itemSpec, remark, create_by createBy, create_time createTime, shjg, moctyUuid
FROM mo_picking_summary WHERE create_by = #{createBy}

    AND doc_no = #{docNo}


    AND id = #{id}


    AND item_code = #{itemCode}

SELECT COUNT(1) FROM mo_picking_summary
WHERE match_qty = business_qty
AND id = #{id}

SELECT id, doc_no docNo, item_code itemCode, business_qty businessQty,
match_qty matchQty, current_num currentNum, warehouse_code warehouseCode,
warehouse_name warehouseName, bin_code binCode, unit_code unitCode, unit_name unitName, barcode,
item_name itemName, item_spec itemSpec, remark, create_by createBy, create_time createTime
FROM mo_picking_summary WHERE create_by = #{createBy}

    AND doc_no = #{docNo}


    AND id = #{id}
